const fs = require('fs');
const path = require('path');

const workDir = '/Users/orion/Documents/大都会-通联';

function scanDir(dir, prefix = '') {
  const items = fs.readdirSync(dir, { withFileTypes: true });
  let result = [];
  for (const item of items) {
    if (item.name.startsWith('.')) continue; // 跳过隐藏文件
    const fullPath = path.join(dir, item.name);
    const relPath = prefix ? `${prefix}/${item.name}` : item.name;
    if (item.isDirectory()) {
      result.push(`📁 ${relPath}/`);
      result = result.concat(scanDir(fullPath, relPath));
    } else {
      const stat = fs.statSync(fullPath);
      const sizeKB = (stat.size / 1024).toFixed(1);
      result.push(`📄 ${relPath}  (${sizeKB} KB)`);
    }
  }
  return result;
}

try {
  const lines = scanDir(workDir);
  if (lines.length === 0) {
    console.log('（目录为空）');
  } else {
    lines.forEach(l => console.log(l));
  }
} catch (e) {
  console.error('扫描失败:', e.message);
}
